package com.example.enterpriseapp.service;

import com.example.enterpriseapp.entity.AppUser;
import com.example.enterpriseapp.repository.AppUserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.util.List;
import java.util.Optional;

@Service
@Transactional
public class UserService {
    private final AppUserRepository appUserRepository;

    public UserService(AppUserRepository appUserRepository) {
        this.appUserRepository = appUserRepository;
    }

    public AppUser createUser(AppUser user) {
        if (appUserRepository.existsByUsername(user.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (appUserRepository.existsByEmail(user.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }
        return appUserRepository.save(user);
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> getUserById(Long id) {
        return appUserRepository.findById(id);
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> getUserByUsername(String username) {
        return appUserRepository.findByUsername(username);
    }

    @Transactional(readOnly = true)
    public List<AppUser> getAllUsers() {
        return appUserRepository.findAll();
    }

    public AppUser updateUser(Long id, AppUser updated) {
        AppUser user = appUserRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setUsername(updated.getUsername());
        user.setEmail(updated.getEmail());
        if (updated.getPasswordHash() != null && !updated.getPasswordHash().isBlank()) {
            user.setPasswordHash(updated.getPasswordHash());
        }
        user.setEnabled(updated.isEnabled());
        return appUserRepository.save(user);
    }

    public void deleteUser(Long id) {
        if (!appUserRepository.existsById(id)) {
            throw new IllegalArgumentException("User not found");
        }
        appUserRepository.deleteById(id);
    }
}

package com.example.enterpriseapp.service;

import com.example.enterpriseapp.entity.TransactionRecord;
import com.example.enterpriseapp.repository.TransactionRecordRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.math.BigDecimal;
import java.util.List;

@Service
@Transactional
public class TransactionService {
    private final TransactionRecordRepository transactionRecordRepository;

    public TransactionService(TransactionRecordRepository transactionRecordRepository) {
        this.transactionRecordRepository = transactionRecordRepository;
    }

    public TransactionRecord createTransaction(Long userId, BigDecimal amount, String type) {
        TransactionRecord tx = new TransactionRecord(userId, amount, type, "PENDING");
        return transactionRecordRepository.save(tx);
    }

    public TransactionRecord updateStatus(Long id, String status) {
        TransactionRecord tx = transactionRecordRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        tx.setStatus(status);
        return transactionRecordRepository.save(tx);
    }

    @Transactional(readOnly = true)
    public List<TransactionRecord> getTransactionsForUser(Long userId) {
        return transactionRecordRepository.findByUserId(userId);
    }

    @Transactional(readOnly = true)
    public List<TransactionRecord> getTransactionsByStatus(String status) {
        return transactionRecordRepository.findByStatus(status);
    }

    @Transactional(readOnly = true)
    public List<TransactionRecord> getAllTransactions() {
        return transactionRecordRepository.findAll();
    }

    public void deleteTransaction(Long id) {
        if (!transactionRecordRepository.existsById(id)) {
            throw new IllegalArgumentException("Transaction not found");
        }
        transactionRecordRepository.deleteById(id);
    }
}

package com.example.enterpriseapp.controller;

import com.example.enterpriseapp.entity.AppUser;
import com.example.enterpriseapp.service.UserService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.util.List;

@RestController
@RequestMapping("/api/users")
public class UserController {
    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping
    public ResponseEntity<AppUser> createUser(@RequestBody AppUser user) {
        return ResponseEntity.ok(userService.createUser(user));
    }

    @GetMapping("/{id}")
    public ResponseEntity<AppUser> getUser(@PathVariable Long id) {
        return userService.getUserById(id)
                .map(ResponseEntity::ok)
                .orElse(ResponseEntity.notFound().build());
    }

    @GetMapping
    public ResponseEntity<List<AppUser>> getAllUsers() {
        return ResponseEntity.ok(userService.getAllUsers());
    }

    @PutMapping("/{id}")
    public ResponseEntity<AppUser> updateUser(@PathVariable Long id, @RequestBody AppUser user) {
        return ResponseEntity.ok(userService.updateUser(id, user));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteUser(@PathVariable Long id) {
        userService.deleteUser(id);
        return ResponseEntity.noContent().build();
    }
}

package com.example.enterpriseapp.controller;

import com.example.enterpriseapp.entity.TransactionRecord;
import com.example.enterpriseapp.service.TransactionService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.math.BigDecimal;
import java.util.List;

@RestController
@RequestMapping("/api/transactions")
public class TransactionController {
    private final TransactionService transactionService;

    public TransactionController(TransactionService transactionService) {
        this.transactionService = transactionService;
    }

    @PostMapping
    public ResponseEntity<TransactionRecord> createTransaction(@RequestParam Long userId,
                                                               @RequestParam BigDecimal amount,
                                                               @RequestParam String type) {
        return ResponseEntity.ok(transactionService.createTransaction(userId, amount, type));
    }

    @PatchMapping("/{id}/status")
    public ResponseEntity<TransactionRecord> updateStatus(@PathVariable Long id,
                                                           @RequestParam String status) {
        return ResponseEntity.ok(transactionService.updateStatus(id, status));
    }

    @GetMapping("/user/{userId}")
    public ResponseEntity<List<TransactionRecord>> getTransactionsForUser(@PathVariable Long userId) {
        return ResponseEntity.ok(transactionService.getTransactionsForUser(userId));
    }

    @GetMapping
    public ResponseEntity<List<TransactionRecord>> getAllTransactions() {
        return ResponseEntity.ok(transactionService.getAllTransactions());
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteTransaction(@PathVariable Long id) {
        transactionService.deleteTransaction(id);
        return ResponseEntity.noContent().build();
    }
}

